-- Migration: 037_feature_practica_catalogo
-- Descripcion: Catalogo de practicas medicas con precios Bono B y Bono C
-- Importado desde practicas.csv

CREATE SCHEMA IF NOT EXISTS sch_hca;

CREATE TABLE IF NOT EXISTS sch_hca.practica_catalogo (
    id SERIAL PRIMARY KEY,
    codigo VARCHAR(20) NOT NULL,
    nombre VARCHAR(500) NOT NULL,
    categoria VARCHAR(200),
    nombre_completo VARCHAR(600),
    bono_b NUMERIC(12,2) DEFAULT 0,
    bono_c NUMERIC(12,2) DEFAULT 0,
    activa BOOLEAN DEFAULT true,
    created_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_practica_catalogo_codigo ON sch_hca.practica_catalogo(codigo);
CREATE INDEX IF NOT EXISTS idx_practica_catalogo_categoria ON sch_hca.practica_catalogo(categoria);